async function emitDirectoryHints(
  baseDir: string,
  filesLoaded: number,
  configsLoaded: number,
): Promise<void> {
  for (const [dir, section, loaded, sidecar] of [
    ["files", "files", filesLoaded, "files-manifest.json"],
    ["configs", "configs", configsLoaded, "configs-manifest.json"],
  ] as const) {
    try {
      await access(path.join(baseDir, dir));
      if ((loaded as number) === 0) {
        logger.info(
          `Detected ${dir}/ directory — create ${sidecar} at the repo root to have init populate ${section} entries automatically.`,
        );
      }
    } catch {
      // directory does not exist — silent
    }
  }
}

async function manifestExists(manifestPath: string): Promise<boolean> {
  try {
    await access(manifestPath);
    return true;
  } catch {
    return false;
  }
}

function logVerboseManifest(
  skills: SkillEntry[],
  agentRules: AgentRuleEntry[],
  mcpServers: McpServerEntry[],
  files: FileEntry[],
  configs: ConfigEntry[],
): void {
  for (const s of skills) {
    logger.detail(`${s.name}  →  ${s.path}`);
  }
  if (agentRules.length > 0) {
    logger.detail("agentRules:");
    for (const r of agentRules) {
      logger.detail(`  ${r.name}  →  ${r.path}  [${r.agents.join(", ")}]`);
    }
  }
  if (mcpServers.length > 0) {
    logger.detail("mcpServers:");
    for (const m of mcpServers) {
      logger.detail(`  ${m.name}  [${m.agents.join(", ")}]`);
    }
  }
  if (files.length > 0) {
    logger.detail("files:");
    for (const f of files) {
      logger.detail(`  ${f.name}  →  ${f.target}  [${f.agents.join(", ")}]`);
    }
  }
  if (configs.length > 0) {
    logger.detail("configs:");
    for (const c of configs) {
      logger.detail(`  ${c.name}  →  ${c.target}  [${c.agents.join(", ")}]`);
    }
  }
}

export interface InitOptions {
  directory: string;
  agents: AgentId[] | null;
  dryRun: boolean;
  force: boolean;
  verbose: boolean;
}

export async function runInit(options: InitOptions): Promise<number> {
  const { directory, dryRun, force, verbose } = options;
  const agents: AgentId[] = options.agents ?? ([...AGENT_IDS] as AgentId[]);
  const agentRulesCapableAgents = agents.filter(
    (id) =>
      AGENT_REGISTRY_BY_ID[id].agentRulesSupport?.status !== "unsupported",
  );

  const manifestPath = path.join(directory, "inception.json");

  if (!dryRun && (await manifestExists(manifestPath)) && !force) {
    logger.error(
      `Error: ${manifestPath} already exists. Use --force to overwrite.`,
    );
    return 2;
  }

  const found: Array<{ relPath: string; name: string }> = [];
  await findSkillDirs(directory, directory, found);

  if (found.length === 0) {
    logger.info(
      "No skill directories found (looking for directories containing SKILL.md).",
    );
  }

  const skills = buildSkills(found, agents);
  const skillNamesSeen = new Set(skills.map((s) => s.name));
  const skillDirRelPaths = new Set(found.map((f) => f.relPath));

  const agentRulesCandidates = await findAgentRulesCandidates(
    directory,
    skillDirRelPaths,
  );
  const agentRules = buildAgentRules(
    agentRulesCandidates,
    agentRulesCapableAgents,
    skillNamesSeen,
  );

  const mcpServers = await loadMcpServers(directory);
  const files = await loadFilesManifest(directory);
  const configs = await loadConfigsManifest(directory);

  const manifest = {
    skills,
    files,
    configs,
    mcpServers,
    agentRules,
  };
  const json = `${JSON.stringify(manifest, null, 2)}\n`;

  function summarize(): string {
    const parts = [
      `${skills.length} skill(s)`,
      `${agentRules.length} agentRule(s)`,
      `${mcpServers.length} mcpServer(s)`,
      `${files.length} file(s)`,
      `${configs.length} config(s)`,
    ];
    return parts.join(", ");
  }

  if (dryRun) {
    logger.info(
      `${dryRunPrefix(true)}Would write ${manifestPath} with ${summarize()}:`,
    );
    logger.info("");
    logger.info(json);
    await emitDirectoryHints(directory, files.length, configs.length);

import { mkdir, readFile, rename, rm, writeFile } from "node:fs/promises";
import { createRequire } from "node:module";
import path from "node:path";

const _require = createRequire(import.meta.url);
// front-matter is a CommonJS module whose export is the callable parse function.
const parseFrontmatter = _require("front-matter") as <T>(input: string) => {
  attributes: T;
  body: string;
};

// ---------------------------------------------------------------------------
// Hand-rolled flat-YAML serializer
// Handles the shapes found in MCP server descriptors: strings, numbers,
// booleans, string arrays, and one-level nested objects (e.g. "env").
// ---------------------------------------------------------------------------

function serializeScalar(value: string | number | boolean): string {
  if (typeof value === "string") {
    const needsQuotes = /[:#[\]{},|>&*!'"@`]|^\s|\s$/.test(value);
    return needsQuotes
      ? `"${value.replace(/\\/g, "\\\\").replace(/"/g, '\\"')}"`
      : value;
  }
  return String(value);
}

function serializeArray(key: string, arr: unknown[], pad: string): string {
  if (arr.length === 0) return `${pad}${key}: []`;
  const items = arr.map((item) => {
    const scalar =
      typeof item === "string" ||
      typeof item === "number" ||
      typeof item === "boolean"
        ? serializeScalar(item as string | number | boolean)
        : JSON.stringify(item);
    return `${pad}  - ${scalar}`;
  });
  return [`${pad}${key}:`, ...items].join("\n");
}

function serializeObject(
  key: string,
  obj: Record<string, unknown>,
  pad: string,
): string {
  const inner = serializeFrontmatterAtDepth(obj, `${pad}  `);
  return inner ? `${pad}${key}:\n${inner}` : `${pad}${key}: {}`;
}

function serializeFrontmatterAtDepth(
  data: Record<string, unknown>,
  pad: string,
): string {
  const lines: string[] = [];
  for (const [key, value] of Object.entries(data)) {
    if (value === null || value === undefined) continue;
    if (Array.isArray(value)) {
      lines.push(serializeArray(key, value, pad));
    } else if (typeof value === "object") {
      lines.push(serializeObject(key, value as Record<string, unknown>, pad));
    } else {
      lines.push(
        `${pad}${key}: ${serializeScalar(value as string | number | boolean)}`,
      );
    }
  }
  return lines.join("\n");
}

/**
 * Serializes a flat (one-level) object to a YAML block suitable for use inside
 * `---` frontmatter delimiters.
 */
export function serializeFrontmatter(data: Record<string, unknown>): string {
  return serializeFrontmatterAtDepth(data, "");
}

/**
 * Builds the full content of a frontmatter-bearing Markdown file.
 * If `body` is provided it is appended after the closing delimiter.
 */
export function buildFrontmatterDocument(
  frontmatter: Record<string, unknown>,
  body = "",
): string {
  const serialized = serializeFrontmatter(frontmatter);
  return `---\n${serialized}\n---\n${body}`;
}

function createAtomicTempPath(targetPath: string): string {
  return `${targetPath}.inception-tmp-${process.pid}-${Date.now()}-${Math.random()
    .toString(36)
    .slice(2)}`;
}

/**
 * Reads an existing `.md` file and parses its frontmatter (using the
 * `front-matter` package). Returns the parsed attributes and raw body.
 * Returns `{ attributes: {}, body: "" }` if the file does not exist.
 */
export async function readFrontmatterFile(filePath: string): Promise<{
  attributes: Record<string, unknown>;
  body: string;
}> {
  let raw: string;
  try {
    raw = await readFile(filePath, "utf-8");
  } catch (err) {
    const code = (err as NodeJS.ErrnoException).code;
    if (code === "ENOENT") return { attributes: {}, body: "" };
    throw err;
  }
  const parsed = parseFrontmatter<Record<string, unknown>>(raw);
  return { attributes: parsed.attributes, body: parsed.body };
}

/**
 * Atomically writes a Markdown file with the given frontmatter and optional
 * body. Preserves any existing body content when `preserveBody` is true.
 */
export async function writeFrontmatterFile(
  filePath: string,
  frontmatter: Record<string, unknown>,
  options: { preserveBody?: boolean } = {},
): Promise<void> {
  let body = "";
  if (options.preserveBody) {
    const existing = await readFrontmatterFile(filePath);
    body = existing.body;
  }
  const content = buildFrontmatterDocument(frontmatter, body);
  const tempPath = createAtomicTempPath(filePath);
  try {
    await mkdir(path.dirname(filePath), { recursive: true });
    await writeFile(tempPath, content, "utf-8");
    await rename(tempPath, filePath);
  } catch (err) {
    try {
      await rm(tempPath, { force: true });
    } catch {
      /* best-effort cleanup */
    }
    throw err;
  }
}

