function serializeArray(key: string, arr: unknown[], pad: string): string {
  if (arr.length === 0) return `${pad}${key}: []`;
  const items = arr.map((item) => {
    const scalar =
      typeof item === "string" ||
      typeof item === "number" ||
      typeof item === "boolean"
        ? serializeScalar(item as string | number | boolean)
        : JSON.stringify(item);
    return `${pad}  - ${scalar}`;
  });
  return [`${pad}${key}:`, ...items].join("\n");
}

